using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // [Fix 1] Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
        // Existing documents use "Discriminator", so preserve the old name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // [Fix 2] id no longer contains discriminator (was "Blog|1", now just "1").
        // Existing documents use the old compound format, so preserve it.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // [Fix 3] HasIndex throws at startup for Cosmos DB entities in EF Core 9.
        // Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

