using Microsoft.EntityFrameworkCore;

class SyncJob
{
    // [Fix 4] Sync I/O (ToList, SaveChanges) no longer supported on Cosmos DB provider
    // in EF Core 9 — throws at runtime. Use async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

